import java.util.*;

public class Solution {
    public static long solve(long n, long k) {
        if (k == 0) {
            return (n >= 1) ? 1 : 0;
        }

        int max_t = 60;
        int[] depth_arr = new int[max_t + 1];
        depth_arr[1] = 0;
        for (int i = 2; i <= max_t; i++) {
            depth_arr[i] = depth_arr[Integer.bitCount(i)] + 1;
        }

        Set<Integer> A = new HashSet<>();
        for (int i = 1; i <= max_t; i++) {
            if (depth_arr[i] == k - 1) {
                A.add(i);
            }
        }

        long total = 0;
        for (int t : A) {
            total += countWithExactPop(n, t);
        }

        if (k == 1 && n >= 1) {
            total--;
        }

        return total;
    }

    private static long countWithExactPop(long n, int t) {
        if (n == 0) {
            return 0;
        }
        List<Integer> bits = new ArrayList<>();
        long num = n;
        while (num > 0) {
            bits.add((int)(num & 1));
            num >>>= 1;
        }
        Collections.reverse(bits);
        int L = bits.size();

        if (t > L) {
            return 0;
        }

        long[][][] dp = new long[L+1][t+1][2];
        dp[0][0][1] = 1;

        for (int i = 0; i < L; i++) {
            for (int ones = 0; ones <= t; ones++) {
                for (int tight = 0; tight < 2; tight++) {
                    if (dp[i][ones][tight] == 0) 
                        continue;
                    int upper = (tight == 1) ? bits.get(i) : 1;
                    for (int d = 0; d <= upper; d++) {
                        int nextOnes = ones + (d == 1 ? 1 : 0);
                        if (nextOnes > t) 
                            continue;
                        int nextTight = (tight == 1) && (d == bits.get(i)) ? 1 : 0;
                        dp[i+1][nextOnes][nextTight] += dp[i][ones][tight];
                    }
                }
            }
        }

        return dp[L][t][0] + dp[L][t][1];
    }
}
