    public static long solve(long n, long k) {
        if (k == 0) {
            return 1;
        }

        int[] dep = new int[61];
        for (int i = 1; i <= 60; i++) {
            if (i == 1) {
                dep[i] = 0;
            } else {
                int pop = Integer.bitCount(i);
                dep[i] = 1 + dep[pop];
            }
        }

        Set<Integer> T = new HashSet<>();
        for (int a = 1; a <= 60; a++) {
            if (dep[a] == k - 1) {
                T.add(a);
            }
        }

        long total = countPopcountInSet(n, T);
        if (k == 1) {
            total -= 1;
        }
        return total;
    }

    private static long countPopcountInSet(long n, Set<Integer> T) {
        if (n == 0) {
            return T.contains(0) ? 1 : 0;
        }
        String s = Long.toBinaryString(n);
        int len = s.length();
        long[][][] dp = new long[len + 1][2][len + 1];
        dp[0][1][0] = 1;

        for (int i = 0; i < len; i++) {
            int bit = s.charAt(i) - '0';
            for (int tight = 0; tight < 2; tight++) {
                for (int ones = 0; ones <= len; ones++) {
                    if (dp[i][tight][ones] == 0) continue;
                    int maxDigit = (tight == 1) ? bit : 1;
                    for (int d = 0; d <= maxDigit; d++) {
                        int newTight = (tight == 1 && d == maxDigit) ? 1 : 0;
                        int newOnes = ones + (d == 1 ? 1 : 0);
                        dp[i + 1][newTight][newOnes] += dp[i][tight][ones];
                    }
                }
            }
        }

        long total = 0;
        for (int tight = 0; tight < 2; tight++) {
            for (int ones = 0; ones <= len; ones++) {
                if (T.contains(ones)) {
                    total += dp[len][tight][ones];
                }
            }
        }
        return total;
    }
}
